SELECT COUNT(*) AS fraud_transaction_count
FROM transactions
WHERE is_fraud = 1;

SELECT DISTINCT t.user_id
FROM transactions t
JOIN fraud_transactions ft ON t.transaction_id = ft.transaction_id;

SELECT COUNT(*) AS fraud_transaction_count
FROM transactions
WHERE is_fraud = 1;

SELECT review_status, AVG(fraud_score) AS average_fraud_score
FROM fraud_transactions
WHERE review_status = 'Pending';

SELECT AVG(amount) AS average_fraudulent_transaction_amount
FROM transactions
WHERE is_fraud = 1;

SELECT mcc_description, average_transaction_amount
FROM mcc_codes
WHERE is_fraud_sensitive = 1;
